import React, {useEffect, useState, useRef} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import ListingCard from '../components/ListingCard'
import {useDispatch, useSelector} from 'react-redux'
import {addFilter, removeFilter} from '../redux/shopSlice'
import FilterSection from '../components/FilterSection'
import {shopSelector} from '../redux/shopSlice.js'

const ShopContentWrapper = styled.div `
width:80%;
margin:30px auto;
display:flex;
`

const SidebarWrapper = styled.div `
width:25%;
`

const Listings = styled.div `
width:100%;
display:flex;
flex-wrap: wrap;
`

const Hr = styled.div `
height:1px;
width:80%;
background-color:#BDC0BA;
margin:0 auto;
`

export default function Shop () {
	const dispatch = useDispatch()
	const [listing, setListing] = useState([])
	const listingRef = useRef([])
	const filterListSelector = useSelector(shopSelector)

	useEffect(() => {
		(async () => {
			const result = await fetch('http://localhost:5001/shop')
			const data = await result.json()
			setListing(() => {
				let newListing = []
				data.forEach(data => newListing.push(data))
				return newListing
			})
		})();
	},[])


	const handleCheckboxChange = (e, target) => {
		const filterTargetId = Object.entries(target)[0][1]
		const filterTarget = Object.keys(target)[0]

		if (e.target.checked) {
			dispatch(addFilter(e.target.value))
			listingRef.current.push(`${filterTarget}=${filterTargetId}`)	
		} else {
			for (let i = 0 ; i < listingRef.current.length ; i++) {
				dispatch(removeFilter(e.target.value))
				if (listingRef.current[i] === `${filterTarget}=${filterTargetId}`) {
					listingRef.current.splice(i, 1)
				}
			}
		}

		const APIEndPoint = listingRef.current.join('&');
		(async function getData() {
			const result = await fetch(`http://localhost:5001/filter?${APIEndPoint}`)
			const data = await result.json()
			setListing(() => {
				let newListing = []
				data.forEach(listing => newListing.push(listing))
				return newListing
			})
		})();		
	}

	return (
		<>
			<Header />
			<Navbar />
			<FilterSection />
			{filterListSelector.filter.length > 0 ? <Hr /> : null}
			<ShopContentWrapper>
				<SidebarWrapper>
					<Sidebar handleCheckboxChange={handleCheckboxChange}/>
				</SidebarWrapper>
				<Listings>
					{listing.map(listing => <ListingCard key={listing.id}>{listing}</ListingCard>)}
				</Listings>
			</ShopContentWrapper>
		</>
	)
}
